class Solution:
    def restoreIpAddresses(self, s: str) -> List[str]:
        res = []
        def ok(seg):
            return len(seg) <= 3 and (seg[0] != '0' or len(seg) == 1) and int(seg) <= 255
        def dfs(i, parts):
            if len(parts) == 4:
                if i == len(s): res.append('.'.join(parts))
                return
            for j in range(i + 1, min(i + 4, len(s) + 1)):
                seg = s[i:j]
                if ok(seg): dfs(j, parts + [seg])
        dfs(0, [])
        return res

