class Solution {
    vector<string> res;
    bool ok(const string& t) {
        if (t.size()>3 || (t.size()>1 && t[0]=='0')) return false;
        return stoi(t)<=255;
    }
    void dfs(string& s, int i, vector<string>& p) {
        if ((int)p.size()==4) { if (i==(int)s.size()) res.push_back(p[0]+"."+p[1]+"."+p[2]+"."+p[3]); return; }
        for (int j=i+1;j<=min(i+3,(int)s.size());j++) {
            string seg=s.substr(i,j-i); if (!ok(seg)) continue;
            p.push_back(seg); dfs(s,j,p); p.pop_back();
        }
    }
public:
    vector<string> restoreIpAddresses(string s) {
        vector<string> p; dfs(s,0,p); return res;
    }
};
